const wh = $('Webhook Trigger').first().json;
const body = wh.body || wh;
const merchantArr = $('Find Merchant').first().json;
const merchant = (Array.isArray(merchantArr) && merchantArr.length > 0) ? merchantArr[0] : (merchantArr || {});
const clientResp = $('Identify Client').first().json;
const client = Array.isArray(clientResp) && clientResp.length > 0 ? clientResp[0] : (clientResp && clientResp.id ? clientResp : {});

// Nom "reel" : present en BDD ET pas le placeholder 'Inconnu'.
// On NE saouve PAS le sender_name WhatsApp a la creation (cf. Identify Client p_name=''),
// donc client.name = 'Inconnu' tant que le client n'a pas donne son prenom via Gemini.
const dbName = (client.name && client.name !== 'Inconnu') ? client.name : null;

return [{json: {
  channel: body.channel || 'whatsapp',
  sender_id: body.sender_phone || body.sender_id,
  sender_name: body.sender_name,
  message_text: body.message_text || '',
  wa_message_id: body.wa_message_id,
  wa_phone_number_id: body.wa_phone_number_id,
  timestamp: body.timestamp,
  merchant_id: merchant.id,
  salon_name: merchant.name || 'Salon',
  ai_name: merchant.ai_name || 'AurA',
  ai_tone: merchant.ai_tone || 'friendly',
  cancellation_delay_minutes: merchant.cancellation_delay_minutes || 120,
  opening_hours: merchant.opening_hours || {},
  client_id: client.id,
  client_name: dbName || body.sender_name || 'Inconnu',
  client_db_name: dbName,
  loyalty_points: client.loyalty_points || 0,
  preferred_service: client.preferred_service_id || 'aucun',
  preferred_practitioner: client.preferred_practitioner_id || 'aucun'
}}];

/**
 * Prepare Context for AI Agent v3.13
 * v3.13: detection date PRIORISE message courant > historique (evite collision dates anciennes)
 */
const MAX_MSG = 500;
const MAX_HIST = 15;
const MAX_BOOKING_DAYS_AHEAD = 60;

function san(s, max) {
  if (!s) return '';
  s = String(s);
  const patterns = ['system:', 'assistant:', 'admin:', 'ACT AS', 'INSTRUCTIONS:'];
  for (const p of patterns) {
    while (s.toLowerCase().includes(p.toLowerCase())) {
      s = s.replace(new RegExp(p, 'gi'), '[FILTERED]');
    }
  }
  return s.length > max ? s.substring(0, max) + '...' : s;
}

function normalize(s) {
  return String(s || '').toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/['-]/g, ' ');
}

function extractGivenName(text) {
  if (!text) return null;
  const t = String(text).trim();
  const patterns = [
    /je\s+m\s*appelle\s+([A-Za-zÀ-ÿ-]{2,30})/i,
    /c\s*est\s+([A-Za-zÀ-ÿ-]{2,30})/i,
    /moi\s+c\s*est\s+([A-Za-zÀ-ÿ-]{2,30})/i,
    /mon\s+(?:pr[eé]nom|nom)\s+(?:c\s*est\s+)?([A-Za-zÀ-ÿ-]{2,30})/i,
    /appelez[\s-]moi\s+([A-Za-zÀ-ÿ-]{2,30})/i
  ];
  for (const p of patterns) {
    const m = t.match(p);
    if (m) return m[1].trim();
  }
  if (/^[A-Za-zÀ-ÿ-]{2,30}$/.test(t)) return t;
  return null;
}

const MONTH_MAP = {
  'janvier': 1, 'fevrier': 2, 'mars': 3, 'avril': 4, 'mai': 5, 'juin': 6,
  'juillet': 7, 'aout': 8, 'septembre': 9, 'octobre': 10, 'novembre': 11, 'decembre': 12
};

const ctx = $('Build Context').first().json;
const merchant = $('Find Merchant').first().json;

let svcItems = [];
try {
  svcItems = $('Load Services').all().map(i => i.json).filter(s => s.name);
} catch(e) {}
let svcList = svcItems.length
  ? svcItems.map(s => {
      const p = s.price_cents ? ', ' + (s.price_cents / 100).toFixed(0) + 'E' : '';
      return s.name + ' [id:' + s.id + '] (' + s.duration_minutes + ' min' + p + ')';
    }).join(', ')
  : 'Aucun service actif';

let pracList = 'Aucun praticien';
try {
  const items = $('Load Practitioners').all().map(i => i.json).filter(p => p.name);
  const seen = new Set();
  if (items.length) pracList = items.filter(p => {
    if (seen.has(p.id)) return false;
    seen.add(p.id);
    return true;
  }).map(p => p.name + ' [id:' + p.id + ']').join(', ');
} catch(e) {}

let bookingsArr = [];
try {
  bookingsArr = $('Load Client Bookings').all().map(i => i.json).filter(b => b.starts_at);
} catch(e) {}
let bkList = 'Aucun RDV a venir';
if (bookingsArr.length) {
  const f = new Intl.DateTimeFormat('fr-FR', {
    timeZone: 'Europe/Paris', weekday: 'long', day: 'numeric',
    month: 'long', hour: '2-digit', minute: '2-digit'
  });
  bkList = bookingsArr.map(b =>
    (b.service_name || 'RDV') + ' avec ' + (b.practitioner_name || '?') +
    ' le ' + f.format(new Date(b.starts_at)) + ' (id:' + b.booking_id + ')'
  ).join('; ');
}

let cov = 'aucun';
try {
  const pkgs = [].concat($('Check Client Packages').first()?.json || []).filter(c => c?.package?.is_active);
  const subs = [].concat($('Check Client Subscriptions').first()?.json || []);
  const parts = [];
  pkgs.forEach(c => parts.push('Forfait ' + (c.package?.name || 'inconnu') + ' (' + c.remaining_uses + ' restantes)'));
  subs.forEach(c => parts.push('Abo ' + (c.name || c.id || 'inconnu') + ' (actif)'));
  if (parts.length) cov = parts.join(', ');
} catch(e) {}

let histMsgs = [];
let hasH = false;
try {
  histMsgs = $('Load Conversation History').all().map(i => i.json)
    .filter(m => m.content && m.sender)
    .sort((a, b) => (a.created_at || '').localeCompare(b.created_at || ''))
    .slice(-MAX_HIST);
  if (histMsgs.length) hasH = true;
} catch(e) {}
const hist = histMsgs.length
  ? histMsgs.map(m => '[' + (m.sender === 'ai' ? 'IA' : 'Client') + '] ' + m.content).join('\n')
  : 'Premiere interaction';

const tz = 'Europe/Paris';
const now = DateTime.now().setZone(tz);
const wd = now.weekday;
const gw = (now.hour >= 18 || now.hour < 5) ? 'Bonsoir' : 'Bonjour';
const nwd = t => {
  const d = ((t - wd + 7) % 7) || 7;
  return now.plus({ days: d }).toFormat('yyyy-MM-dd');
};
const td = now.toFormat('yyyy-MM-dd');
const tl = now.setLocale('fr').toFormat('cccc d MMMM yyyy');
const tm = now.plus({ days: 1 }).toFormat('yyyy-MM-dd');
const da = now.plus({ days: 2 }).toFormat('yyyy-MM-dd');
const maxBookingDate = now.plus({ days: MAX_BOOKING_DAYS_AHEAD }).toFormat('yyyy-MM-dd');
const maxBookingDateHumanFr = now.plus({ days: MAX_BOOKING_DAYS_AHEAD }).setLocale('fr').toFormat('cccc d MMMM yyyy');

let scopeStartIdx = 0;
for (let i = histMsgs.length - 1; i >= 0; i--) {
  const m = histMsgs[i];
  if (m.sender !== 'ai') continue;
  const cNorm = normalize(m.content);
  if (/confirme|rendez vous est/.test(cNorm)) {
    scopeStartIdx = i + 1;
    break;
  }
}
const scopedMsgs = histMsgs.slice(scopeStartIdx);
const currentMsgNorm = normalize(ctx.message_text || '');
const historyMsgsNorm = normalize(
  scopedMsgs.filter(m => m.sender !== 'ai').map(m => m.content).join(' ')
);
const clientText = historyMsgsNorm + ' ' + currentMsgNorm;

let detectedService = null;
let detectedSvcDuration = null;
let detectedSvcId = null;
for (const svc of svcItems) {
  const tokens = normalize(svc.name).split(/\s+/).filter(t => t.length >= 3);
  for (const tok of tokens) {
    if (clientText.includes(tok)) {
      detectedService = svc.name + ' [id:' + svc.id + ', ' + svc.duration_minutes + 'min]';
      detectedSvcDuration = svc.duration_minutes;
      detectedSvcId = svc.id;
      break;
    }
  }
  if (detectedService) break;
}

let detectedDate = null;
let detectedDateHumanFr = null;
let detectedDateOutOfRange = false;

function toHumanFr(isoDate) {
  try {
    return DateTime.fromISO(isoDate, { zone: tz }).setLocale('fr').toFormat('cccc d MMMM');
  } catch(e) { return isoDate; }
}

// Try to extract date from a given text. Priority: X mois > X/MM > jour de semaine
function extractDate(text) {
  if (!text) return null;
  const monthMatch = text.match(/(?:le\s+)?(\d{1,2})\s+(janvier|fevrier|mars|avril|mai|juin|juillet|aout|septembre|octobre|novembre|decembre)/);
  if (monthMatch) {
    const day = parseInt(monthMatch[1], 10);
    const month = MONTH_MAP[monthMatch[2]];
    if (day >= 1 && day <= 31 && month) {
      let year = now.year;
      const candidate = DateTime.fromObject({ year, month, day }, { zone: tz });
      if (candidate.isValid && candidate < now.startOf('day')) year++;
      const final = DateTime.fromObject({ year, month, day }, { zone: tz });
      if (final.isValid) return final;
    }
  }
  const slashMatch = text.match(/(\d{1,2})[\/-](\d{1,2})(?:[\/-](\d{2,4}))?/);
  if (slashMatch) {
    const day = parseInt(slashMatch[1], 10);
    const month = parseInt(slashMatch[2], 10);
    let year = slashMatch[3] ? parseInt(slashMatch[3], 10) : now.year;
    if (year < 100) year += 2000;
    if (day >= 1 && day <= 31 && month >= 1 && month <= 12) {
      const final = DateTime.fromObject({ year, month, day }, { zone: tz });
      if (final.isValid) return final;
    }
  }
  const dateMap = [
    ['aujourd hui', td], ['ce soir', td], ['demain', tm], ['apres demain', da],
    ['lundi', nwd(1)], ['mardi', nwd(2)], ['mercredi', nwd(3)], ['jeudi', nwd(4)],
    ['vendredi', nwd(5)], ['samedi', nwd(6)], ['dimanche', nwd(7)]
  ];
  for (const [kw, dt] of dateMap) {
    if (text.includes(kw)) return DateTime.fromISO(dt, { zone: tz });
  }
  return null;
}

// PRIORITE 1 : message courant uniquement
let dateDt = extractDate(currentMsgNorm);
// FALLBACK : si rien dans le message courant, chercher dans l'historique
if (!dateDt) dateDt = extractDate(historyMsgsNorm);

if (dateDt) {
  detectedDate = dateDt.toFormat('yyyy-MM-dd');
  detectedDateHumanFr = dateDt.setLocale('fr').toFormat('cccc d MMMM yyyy');
  const daysDiff = dateDt.diff(now.startOf('day'), 'days').days;
  if (daysDiff > MAX_BOOKING_DAYS_AHEAD) {
    detectedDateOutOfRange = true;
  }
}

let detectedTime = null;
if (clientText.includes('matin')) detectedTime = 'matin (entre 7h et 12h)';
else if (clientText.includes('apres midi') || clientText.includes('aprem')) detectedTime = 'apres-midi (entre 12h et 18h)';
else if (clientText.includes('soir')) detectedTime = 'soir (apres 18h)';

const regrouperIntent = /regrouper|combiner|joindre|coller|enchainer|enchaine|juste avant|juste apres|en suite|cote a cote/.test(clientText);

const nameMissing = !ctx.client_db_name;
let givenName = null;
let aiAskedName = false;
if (nameMissing) {
  const lastAi = [...histMsgs].reverse().find(m => m.sender === 'ai');
  if (lastAi) {
    aiAskedName = /comment\s+dois\s+je\s+vous\s+appeler|votre\s+prenom|comment\s+vous\s+appelez|quel\s+est\s+votre\s+prenom/i.test(lastAi.content);
  }
  givenName = extractGivenName(ctx.message_text);
}

let lastAiProposedSlot = false;
let lastAiSingleSlotTime = null;
const lastAiMsg = [...histMsgs].reverse().find(m => m.sender === 'ai');
if (lastAiMsg) {
  const c = lastAiMsg.content;
  const hourMatches = c.match(/\b(\d{1,2}h\d{0,2})\b/g);
  if (hourMatches && hourMatches.length > 0) {
    lastAiProposedSlot = true;
    if (hourMatches.length === 1) {
      lastAiSingleSlotTime = hourMatches[0];
    }
  }
}

let nearbyBookings = [];
let adjacentSuggestions = [];
let sameDayBookingsRaw = [];
if (detectedDate && !detectedDateOutOfRange) {
  const target = DateTime.fromISO(detectedDate, { zone: tz });
  for (const b of bookingsArr) {
    const bDate = DateTime.fromISO(b.starts_at, { zone: tz });
    const bEnd = DateTime.fromISO(b.ends_at, { zone: tz });
    const diffDays = Math.abs(bDate.diff(target, 'days').days);
    if (diffDays <= 7) {
      const sameDay = bDate.toFormat('yyyy-MM-dd') === detectedDate;
      nearbyBookings.push({
        date: bDate.setLocale('fr').toFormat('cccc d MMMM à HH:mm'),
        service: b.service_name,
        diff: Math.round(diffDays),
        sameDay
      });
      if (sameDay) {
        sameDayBookingsRaw.push(b);
        if (detectedSvcDuration) {
          adjacentSuggestions.push({
            time: bEnd.toFormat('HH:mm'),
            position: 'apres',
            anchor: b.service_name + ' (' + bDate.toFormat('HH:mm') + '-' + bEnd.toFormat('HH:mm') + ')'
          });
          const beforeStart = bDate.minus({ minutes: detectedSvcDuration });
          adjacentSuggestions.push({
            time: beforeStart.toFormat('HH:mm'),
            position: 'avant',
            anchor: b.service_name + ' (' + bDate.toFormat('HH:mm') + ')'
          });
        }
      }
    }
  }
}

let comboService = null;
let comboReplaceBooking = null;
if (regrouperIntent && detectedSvcId && sameDayBookingsRaw.length > 0) {
  const newSvcKeyword = normalize(detectedService.split(' [')[0]).split(/\s+/)[0];
  for (const b of sameDayBookingsRaw) {
    const existingKeyword = normalize(b.service_name).split(/\s+/)[0];
    if (existingKeyword === newSvcKeyword) continue;
    for (const svc of svcItems) {
      if (svc.id === detectedSvcId) continue;
      const svcName = normalize(svc.name);
      if (svcName.includes(newSvcKeyword) && svcName.includes(existingKeyword)) {
        comboService = {
          id: svc.id,
          name: svc.name,
          duration: svc.duration_minutes,
          price: svc.price_cents ? (svc.price_cents / 100).toFixed(0) + 'E' : 'gratuit'
        };
        comboReplaceBooking = b;
        break;
      }
    }
    if (comboService) break;
  }
}

let warningAlreadyShown = false;
for (let i = scopedMsgs.length - 1; i >= 0; i--) {
  const m = scopedMsgs[i];
  if (m.sender !== 'ai') continue;
  const cNorm = normalize(m.content);
  if (/deja un rendez vous|deja un rdv|deja un autre|meme jour|coller juste|colle juste|votre rendez vous existant|alerte|combo|remplacer/.test(cNorm)) {
    warningAlreadyShown = true;
    break;
  }
}

let warningRdvProche = '';
if (nearbyBookings.length > 0 && !warningAlreadyShown && !regrouperIntent) {
  warningRdvProche = 'ALERTE RDV PROCHES (a mentionner UNE FOIS) :\n';
  for (const nb of nearbyBookings) {
    warningRdvProche += '  - ' + nb.service + ' le ' + nb.date + ' (' + (nb.sameDay ? 'MEME JOUR' : nb.diff + ' jour(s) ecart') + ')\n';
  }
  if (adjacentSuggestions.length > 0) {
    warningRdvProche += 'CRENEAUX CONTIGUS RECOMMANDES :\n';
    for (const adj of adjacentSuggestions) {
      warningRdvProche += '  - ' + adj.time + ' (' + adj.position + ' ' + adj.anchor + ')\n';
    }
    warningRdvProche += '-> Mentionne ce RDV existant + propose le creneau contigu.\n';
  } else {
    warningRdvProche += '-> Mentionne ce RDV proche.\n';
  }
  warningRdvProche += '\n';
}

let regrouperInstruction = '';
if (comboService && !warningAlreadyShown) {
  const bDate = DateTime.fromISO(comboReplaceBooking.starts_at, { zone: tz });
  regrouperInstruction = 'COMBO SERVICE DETECTE — OPTION PRIORITAIRE :\n' +
    '  Service combo dispo : "' + comboService.name + '" (' + comboService.duration + 'min, ' + comboService.price + ')\n' +
    '  RDV existant a remplacer : "' + comboReplaceBooking.service_name + '" le ' + bDate.setLocale('fr').toFormat('cccc d MMMM à HH:mm') + ' (id:' + comboReplaceBooking.booking_id + ')\n' +
    '-> PROPOSE : "Je peux remplacer votre ' + comboReplaceBooking.service_name + ' de ' + bDate.toFormat('HH:mm') + ' par ' + comboService.name + ' (' + comboService.duration + 'min, ' + comboService.price + ') au meme creneau."\n' +
    '-> Si accepte : cancel_booking(booking_id=' + comboReplaceBooking.booking_id + ') PUIS confirm_booking(service_id=' + comboService.id + ', starts_at=' + comboReplaceBooking.starts_at + ').\n\n';
} else if (regrouperIntent && adjacentSuggestions.length > 0) {
  regrouperInstruction = 'INTENT REGROUPER (sans combo dispo) :\n' +
    'Propose UNIQUEMENT les creneaux contigus :\n';
  for (const adj of adjacentSuggestions) {
    regrouperInstruction += '  - ' + adj.time + ' (' + adj.position + ' ' + adj.anchor + ')\n';
  }
  regrouperInstruction += '\n';
}

let dateLimitWarning = '';
if (detectedDateOutOfRange) {
  dateLimitWarning = 'DATE DEMANDEE HORS LIMITE :\n' +
    '  Date client : ' + detectedDate + ' (' + detectedDateHumanFr + ')\n' +
    '  Limite max : ' + maxBookingDate + ' (' + maxBookingDateHumanFr + ')\n' +
    '-> REPONDS poliment : "Desole, nous n\'acceptons les reservations que jusqu\'au ' + maxBookingDateHumanFr + ' (' + MAX_BOOKING_DAYS_AHEAD + ' jours max). Souhaitez-vous un creneau avant cette date ?"\n' +
    '-> NE PROPOSE PAS de creneau.\n\n';
}

let convId = null;
try {
  const ec = $('Ensure Conversation').first().json;
  convId = ec?.id || (Array.isArray(ec) ? ec[0]?.id : null);
} catch(e) {}

const etatActuel = '=== ETAT ACTUEL ===\n' +
'Service identifie : ' + (detectedService || 'AUCUN — a demander') + '\n' +
'Date identifiee  : ' + (detectedDate ? detectedDate + ' (' + detectedDateHumanFr + ')' + (detectedDateOutOfRange ? ' — HORS LIMITE' : '') : 'AUCUNE — a demander') + '\n' +
'Horaire identifie: ' + (detectedTime || 'aucune preference') + '\n' +
'Nom client BDD   : ' + (ctx.client_db_name || 'INCONNU — a demander') + '\n' +
(givenName ? 'PRENOM DONNE PAR CLIENT : "' + givenName + '"\n' : '') +
(aiAskedName ? 'IA a demande le prenom : OUI\n' : '') +
(lastAiSingleSlotTime
  ? 'DERNIER MESSAGE IA proposait UN SEUL creneau : ' + lastAiSingleSlotTime + '\n'
  : (lastAiProposedSlot ? 'DERNIER MESSAGE IA proposait creneaux : OUI\n' : '')) +
(regrouperIntent ? 'INTENT REGROUPER : OUI\n' : '') +
'\n' +
dateLimitWarning +
regrouperInstruction +
warningRdvProche +
'INSTRUCTIONS PRIORITAIRES :\n' +
(givenName
  ? '1. Appelle set_client_name avec client_name="' + givenName + '". Puis reponds "Enchante, ' + givenName + ' !".\n'
  : (nameMissing ? '1. NOM INCONNU : demande le prenom.\n' : '')) +
(detectedDateOutOfRange
  ? '2. DATE HORS LIMITE — refuse poliment.\n'
  : (detectedDate && detectedService
    ? '2. Service ET Date identifies -> get_available_slots IMMEDIATEMENT.\n'
    : (!detectedDate && detectedService
      ? '2. SERVICE OK mais DATE INCONNUE -> DEMANDE LA DATE explicitement.\n'
      : (!detectedService && detectedDate
        ? '2. DATE OK mais SERVICE INCONNU -> DEMANDE LE SERVICE.\n'
        : '2. NI date NI service -> demande les 2.\n')))) +
(lastAiSingleSlotTime
  ? '3. Si reponse positive, confirm_booking IMMEDIATEMENT avec heure=' + lastAiSingleSlotTime + '.\n'
  : '3. Si DERNIER IA proposait creneaux ET client repond "oui"/heure -> confirm_booking IMMEDIATEMENT.\n') +
'\n';

const sys = 'Tu es ' + (ctx.ai_name || 'AurA') + ', assistant IA du salon ' + (ctx.salon_name || 'le salon') + '.\n\n' +
etatActuel +
'=== REGLE 1 ANTI-HALLUCINATION ===\n' +
'INTERDICTION de mentionner date/jour/horaire que tu n\'as PAS calcule via ETAT ACTUEL ou get_available_slots.\n' +
'Si Date AUCUNE : DEMANDE la date.\n' +
'Si Date HORS LIMITE : refuse poliment.\n' +
'Si get_available_slots = 0 : dis "Aucun creneau dispo, autre jour ?"\n\n' +
'=== REGLE 2 SALUTATION ===\n' +
(hasH ? 'Historique existe : pas de Bonjour/Bonsoir.\n\n' :
        'Premiere interaction : commence par ' + gw + '.\n\n') +
'=== REGLE 3 NE JAMAIS REDEMANDER ===\n' +
'Si service/date dans ETAT ACTUEL, NE LES REDEMANDE PAS.\n' +
'MATCHING FUZZY : "barbe" = "Barbe", "coupe" = "Coupe homme".\n\n' +
'=== REGLE 4 INFERENCE DE DATE ===\n' +
'Annee = ' + now.year + '. Tu peux prendre RDV jusqu\'a ' + MAX_BOOKING_DAYS_AHEAD + ' jours (max ' + maxBookingDateHumanFr + ').\n\n' +
'=== REGLE 5 PRESENTATION DES CRENEAUX ===\n' +
'Cas standard : 2-3 creneaux espaces.\n' +
'Si COMBO SERVICE DETECTE : propose le combo (PRIORITE).\n' +
'Si INTENT REGROUPER sans combo : UNIQUEMENT creneaux contigus.\n\n' +
'=== REGLE 6 CONFIRMATION ===\n' +
'Si DERNIER IA proposait creneaux/combo et client repond "oui"/heure -> confirm_booking IMMEDIATEMENT.\n' +
'Si combo accepte : cancel_booking(ancien) PUIS confirm_booking(combo).\n' +
'starts_at ISO 8601 +02:00, ends_at = starts_at + duree.\n\n' +
'=== REGLE 7 FLOW ===\n' +
'1. Service+Date valides -> get_available_slots\n' +
'2. Service sans Date -> demande Date\n' +
'3. Date sans Service -> demande Service\n' +
'4. Propose creneaux\n' +
'5. Client confirme -> confirm_booking\n\n' +
'=== REGLE 8 RDV EXISTANTS ===\n' +
'Source unique = section RDV A VENIR. Si ALERTE RDV PROCHES, mentionne UNE FOIS.\n\n' +
'=== REGLE 9 ===\n' +
'Plusieurs RDV meme jour autorises.\n\n' +
'=== REGLE 10 NOM CLIENT ===\n' +
(givenName
  ? 'Client donne son prenom "' + givenName + '". set_client_name("' + givenName + '") puis remercie.'
  : (nameMissing
    ? 'NOM INCONNU. Demande le prenom. IGNORE noms de l\'historique.'
    : 'Nom : ' + ctx.client_db_name + '. Utilise-le, NE REDEMANDE PAS.')) +
'\n\n' +
'STYLE : Vouvoiement, chaleureux, max 2-3 phrases. Pas "ce" devant un jour.\n\n' +
'AUJOURD\'HUI : ' + tl + '\n' +
'LIMITE RESERVATION : ' + maxBookingDateHumanFr + ' (' + MAX_BOOKING_DAYS_AHEAD + ' jours max)\n\n' +
'DATES (raccourci jours proches) :\n' +
'aujourd\'hui=' + td + ', demain=' + tm + ', apres-demain=' + da + '\n' +
